import{_ as e,o as t,c as _,ae as a}from"./chunks/framework.Bn0jkBmj.js";const u=JSON.parse('{"title":"平时抠门，这次我花千元买了…","description":null,"frontmatter":{"title":null,"description":null},"headers":[],"relativePath":"scl/平时抠门，这次我花千元买了….md","filePath":"scl/平时抠门，这次我花千元买了….md"}'),o={name:"scl/平时抠门，这次我花千元买了….md"};function l(r,p,n,s,c,i){return t(),_("div",null,[...p[0]||(p[0]=[a('<h1 id="平时抠门-这次我花千元买了" tabindex="-1">平时抠门，这次我花千元买了… <a class="header-anchor" href="#平时抠门-这次我花千元买了" aria-label="Permalink to &quot;平时抠门，这次我花千元买了…&quot;">​</a></h1><blockquote><p>本文来自小红书同名账号，转载请注明出处。</p></blockquote><p>有一次， 一段代码总是跑不通， 我一句句一行行，排查了一整天，</p><p>最后的结果，差点惊掉下巴： 我竟然把数字0，看成了字母O。</p><p>面对个低级错误， 我，😛原谅了自己。</p><p>因为我是纯小白，为捣鼓编程， 几乎是整宿整宿，盯着屏幕，</p><p>加上糖尿病并发症， 越来越频繁地感觉： 原先文文静静的字母， 竟在屏幕上…跳广场舞。</p><p>这时，我就往往仰头、 用冷毛巾敷眼睛。</p><p>闭着眼、心里想—— 这般身体“硬件”， 说不定还会、再犯类似的错。</p><p>既然，医生也不能恢复、衰退的视力， 那就不再抠门、直接上“外挂”。</p><p>隔天，我花了1000元， 把一台21吋的高清大屏🖥️， 扛回了家。</p><p>连上电脑，坐在左右两块屏幕前面， 我正调试着，儿子看了看，调侃我： 为什么不顺道，买一件格子衫……</p><p>他哪里知道， 他老爸早就是“夜半码农”了（野生的）。 只是，今天鸟枪换炮了——</p><p>大屏，敲密密麻麻的编程 小屏，就跟上语义注释，</p><p>大屏，是全英文的代码 小屏，就跟着中文教程。</p><p>老婆也进了书房， 双手比划着说： “两个屏幕、一个光头，不开灯都刺眼…”💡</p><p>我懒理她， 我正享受——能轻松看清，大写I和小写l——的舒坦。</p><p>大屏确实不便宜，但是—— 不犯低级错误，比省钱更重要。</p>',18)])])}const m=e(o,[["render",l]]);export{u as __pageData,m as default};
